"""Circle packing: 26 equal circles in hexagonal 5-4-5-4-5-4 arrangement."""
import numpy as np


def construct_packing():
    n = 26
    sqrt3 = np.sqrt(3.0)
    # Hex packing: 6 rows alternating 5,4,5,4,5,4 = 27 circles, take first 26.
    # Vertical: 2r + 5*r*sqrt(3) = 1  -> r = 1/(2+5*sqrt(3)) ~ 0.0938
    # Horizontal: 5 circles need 10r <= 1 -> r <= 0.1 (not binding)
    r_ideal = 1.0 / (2.0 + 5.0 * sqrt3)
    r = r_ideal * 0.9995  # margin: stored radius smaller than placement spacing

    centers = []
    dy = r_ideal * sqrt3
    for i in range(6):
        y = r_ideal + i * dy
        if i % 2 == 0:
            # 5 circles, edges touching left/right
            for j in range(5):
                x = r_ideal + 2.0 * r_ideal * j
                centers.append([x, y])
        else:
            # 4 circles, shifted by r_ideal (hex offset)
            for j in range(4):
                x = 2.0 * r_ideal + 2.0 * r_ideal * j
                centers.append([x, y])
        if len(centers) >= n:
            break

    centers = np.array(centers[:n])
    radii = np.full(n, r)
    return centers, radii, float(np.sum(radii))
# EVOLVE-BLOCK-END


def run_packing():
    return construct_packing()


if __name__ == "__main__":
    centers, radii, sum_radii = run_packing()
    print(f"Sum of radii: {sum_radii:.6f}")

